mapper.select:
SELECT t1.k_code AS kCode, t1.k_name AS kName, t2.start_time AS startTime, t2.end_time AS endTime, t2.area AS area, t2.fee AS fee, t2.first_fee AS firstFee, t2.first_weight AS firstWeight FROM t_customer t1, t_over_fee t2 WHERE t1.k_code = t2.k_code
AND t2.k_code IN
#{kCode}

SELECT t1.k_code AS kCode, t1.k_name AS kName, t2.start_time AS startTime, t2.end_time AS endTime, t2.pre_fee AS prePayment, t3.fee AS fee, t3.area AS area, t3.first_fee AS firstFee FROM t_customer t1, t_prepayment t2, t_over_fee t3 WHERE t1.k_code = t2.k_code AND t2.k_code = t3.k_code AND t2.start_time = t3.start_time AND t2.end_time = t3.end_time
AND t1.k_code IN
#{kCode}
